from fastapi import FastAPI, Depends, HTTPException, Header
from pydantic import BaseModel
import asyncio

app = FastAPI()

class AgentRequest(BaseModel):
    task: str
    context: list[dict] = []   # prior messages, if any
    max_steps: int = 10

class AgentResponse(BaseModel):
    result: str
    steps: int
    usage: dict

def verify_api_key(x_api_key: str = Header(...)):
    if x_api_key not in VALID_KEYS:
        raise HTTPException(status_code=401, detail="Invalid API key")
    return x_api_key

@app.post("/v1/agent/run", response_model=AgentResponse)
async def run_agent(req: AgentRequest, api_key: str = Depends(verify_api_key)):
    try:
        result = await asyncio.wait_for(
            agent_runtime.run(req.task, req.context, req.max_steps),
            timeout=30.0,   # hard cap — adjust per your P99 latency
        )
    except asyncio.TimeoutError:
        raise HTTPException(status_code=504, detail="Agent timed out")
    return AgentResponse(result=result.text, steps=result.steps, usage=result.usage)

from fastapi import FastAPI, Depends
from fastapi.responses import StreamingResponse
from pydantic import BaseModel
import asyncio, json

app = FastAPI()

class StreamRequest(BaseModel):
    task: str
    context: list[dict] = []

async def token_stream(task: str, context: list[dict]):
    """Async generator that yields SSE-formatted token chunks."""
    async for chunk in agent_runtime.stream(task, context):
        # SSE format: each event is "data: <json>\n\n"
        if chunk.type == "token":
            data = json.dumps({"type": "token", "text": chunk.text})
        elif chunk.type == "tool_call":
            data = json.dumps({"type": "tool_call", "name": chunk.name})
        elif chunk.type == "done":
            data = json.dumps({"type": "done", "result": chunk.result})
        else:
            continue
        yield f"data: {data}\n\n"
    # Signal stream end
    yield "data: [DONE]\n\n"

@app.post("/v1/agent/stream")
async def stream_agent(req: StreamRequest, api_key: str = Depends(verify_api_key)):
    return StreamingResponse(
        token_stream(req.task, req.context),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "X-Accel-Buffering": "no",   # disable Nginx buffering
        },
    )

# Client-side (Python — mirrors what a browser EventSource does)
import httpx, json

def run_research_agent(question: str, api_key: str):
    url = "https://api.example.com/v1/agent/stream"
    headers = {"X-API-Key": api_key, "Accept": "text/event-stream"}
    body = {"task": question, "max_steps": 15}

    with httpx.stream("POST", url, headers=headers, json=body, timeout=120) as response:
        response.raise_for_status()
        for line in response.iter_lines():
            if not line.startswith("data:"):
                continue
            payload = line[5:].strip()
            if payload == "[DONE]":
                break
            event = json.loads(payload)
            if event["type"] == "token":
                print(event["text"], end="", flush=True)
            elif event["type"] == "tool_call":
                print(f"\n[tool: {event['name']}]", flush=True)
            elif event["type"] == "done":
                print("\n--- done ---")

run_research_agent("What are the trade-offs between RAG and fine-tuning for domain adaptation?", "my-api-key")
